return [{
  "json": {
    "status": "ok",
    "message": "N8N AI Agent service (Python-powered) is running"
  }
}]

tickets = []

try:
    for item in _input:
        if hasattr(item, 'json'):
            tickets.append(item.json)
        elif isinstance(item, dict) and 'json' in item:
            tickets.append(item['json'])
        else:
            tickets.append(item)
except Exception:
    pass

if not tickets:
    try:
        sheet_data = _("Get row(s) in sheet").all()
        for item in sheet_data:
            if hasattr(item, 'json'):
                tickets.append(item.json)
            elif isinstance(item, dict) and 'json' in item:
                tickets.append(item['json'])
            else:
                tickets.append(item)
    except Exception:
        pass

anomalies = []
for t in tickets:
    status = t.get('status', 'Open')
    priority = t.get('priority', 'Low')

    if status != 'Resolved' and priority in ['High', 'Critical']:
        anomalies.append({
            'ticket_id': t.get('ticket_id'),
            'reason': f"Unresolved {priority} priority ticket",
            **t
        })

    res_time = t.get('resolution_time_hrs')
    if res_time is not None and res_time != '':
        try:
            res_val = float(res_time)
            if res_val > 24:
                anomalies.append({
                    'ticket_id': t.get('ticket_id'),
                    'reason': f"Abnormally long resolution time: {res_val} hrs (expected avg ~5 hrs)",
                    **t
                })
        except ValueError:
            pass

return [{'json': {'anomalies': anomalies}}]

